from urllib.parse import urlparse

def get_target_for_redirect(target: str, domain: str) -> str:
    try:
        parsed_target = urlparse(target)

        # Check if target has a valid scheme and netloc
        if not parsed_target.scheme or not parsed_target.netloc:
            return f'https://{domain}'

        # Ensure https protocol
        if parsed_target.scheme != 'https':
            return f'https://{domain}'

        # Check if the domain matches
        target_domain = parsed_target.netloc
        if target_domain == domain or target_domain.endswith('.' + domain):
            return target
        else:
            return f'https://{domain}'
    except Exception:
        return f'https://{domain}'

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Resolve the full file path
        file_path = os.path.join(dir_path, filename)

        # Get the real paths to prevent directory traversal attacks
        real_file_path = os.path.realpath(file_path)
        real_dir_path = os.path.realpath(dir_path)

        # Ensure the file is within the specified directory
        if not real_file_path.startswith(real_dir_path + os.sep) and not real_file_path == real_dir_path:
            return ""

        # Read the file content
        with open(real_file_path, 'r', encoding='utf-8') as file:
            return file.read()
    except (FileNotFoundError, PermissionError, OSError, UnicodeDecodeError):
        return ""

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not expr or not isinstance(expr, str):
        return ""

    # Remove whitespace
    expr = expr.replace(" ", "")

    # Check for empty expression after whitespace removal
    if not expr:
        return ""

    # Check for potentially dangerous characters/patterns
    dangerous_patterns = ["__", "import", "exec", "eval", "open", "file", "os", "sys", "subprocess"]
    for pattern in dangerous_patterns:
        if pattern in expr.lower():
            return ""

    # Check that expression only contains allowed characters (numbers, basic operators, parentheses, decimal point)
    allowed_chars = set("0123456789+-*/().")
    if not all(c in allowed_chars for c in expr):
        return ""

    try:
        # Use a safer evaluation approach
        # First, try to parse as a literal (for simple numbers)
        import ast
        import operator

        def safe_eval(node):
            if isinstance(node, ast.Constant):  # Python 3.8+
                return node.value
            elif isinstance(node, ast.Num):  # Python < 3.8
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                op = node.op
                if isinstance(op, ast.Add):
                    return left + right
                elif isinstance(op, ast.Sub):
                    return left - right
                elif isinstance(op, ast.Mult):
                    return left * right
                elif isinstance(op, ast.Div):
                    if right == 0:
                        raise ZeroDivisionError("division by zero")
                    return left / right
                else:
                    raise ValueError("Unsupported operation")
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                if isinstance(node.op, ast.USub):
                    return -operand
                else:
                    raise ValueError("Unsupported unary operation")
            elif isinstance(node, ast.Expression):
                return safe_eval(node.body)
            else:
                raise ValueError("Unsupported node type")

        # Parse the expression into an AST
        tree = ast.parse(expr, mode='eval')
        # Evaluate the AST safely
        result = safe_eval(tree)
        # Convert result to string
        return str(result)
    except:
        # Return empty string for any error
        return ""

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=['HS256'])
    except (jwt.InvalidTokenError, jwt.DecodeError, jwt.ExpiredSignatureError):
        return {}

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id or not isinstance(user_id, str):
        return None

    # Sanitize user_id to prevent path traversal attacks
    import re
    if not re.match(r'^[a-zA-Z0-9_-]+$', user_id):
        return None

    # Ensure api_url ends with a slash before concatenating
    if not api_url.endswith('/'):
        api_url += '/'

    return api_url + user_id

