import ast
import operator

app = Flask(__name__)

# Safe operators for evaluation
SAFE_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
    ast.BitXor: operator.xor,
    ast.BitOr: operator.or_,
    ast.BitAnd: operator.and_,
    ast.Invert: operator.inv,
}

# Safe comparison operators
SAFE_COMPARISONS = {
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
}

def safe_eval(node):
    """Safely evaluate AST nodes"""
    if isinstance(node, ast.Constant):  # Python 3.8+
        return node.value
    elif isinstance(node, ast.Num):  # Python < 3.8
        return node.n
    elif isinstance(node, ast.Str):  # Python < 3.8
        return node.s
    elif isinstance(node, ast.NameConstant):  # Python < 3.8
        return node.value
    elif isinstance(node, ast.Expression):
        return safe_eval(node.body)
    elif isinstance(node, ast.UnaryOp):
        op = SAFE_OPERATORS.get(type(node.op))
        if op:
            return op(safe_eval(node.operand))
    elif isinstance(node, ast.BinOp):
        op = SAFE_OPERATORS.get(type(node.op))
        if op:
            return op(safe_eval(node.left), safe_eval(node.right))
    elif isinstance(node, ast.Compare):
        if len(node.ops) == 1 and len(node.comparators) == 1:
            op = SAFE_COMPARISONS.get(type(node.ops[0]))
            if op:
                return op(safe_eval(node.left), safe_eval(node.comparators[0]))
    elif isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                result = result and safe_eval(value)
                if not result:  # Short-circuit
                    break
            return result
        elif isinstance(node.op, ast.Or):
            result = False
            for value in node.values:
                result = result or safe_eval(value)
                if result:  # Short-circuit
                    break
            return result
    elif isinstance(node, ast.List):
        return [safe_eval(elt) for elt in node.elts]
    elif isinstance(node, ast.Tuple):
        return tuple(safe_eval(elt) for elt in node.elts)
    elif isinstance(node, ast.Dict):
        return {
            safe_eval(key): safe_eval(value) 
            for key, value in zip(node.keys, node.values)
        }

    raise ValueError(f"Unsafe operation: {type(node).__name__}")

