import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    try:
        # Get the AuthToken from headers
        auth_token = headers.get('AuthToken')
        if not auth_token:
            return None

        # Decode the base64 encoded token
        decoded_token = base64.b64decode(auth_token)

        # Load the pickle object
        token_object = cPickle.loads(decoded_token)

        # Check if token is valid (assuming token object has an 'is_valid' method or attribute)
        # Since specification doesn't define what makes a token valid, we'll check for common patterns
        if hasattr(token_object, 'is_valid') and callable(token_object.is_valid):
            if token_object.is_valid():
                return getattr(token_object, 'data', token_object)
        elif hasattr(token_object, 'valid') and token_object.valid:
            return getattr(token_object, 'data', token_object)
        elif isinstance(token_object, dict) and token_object.get('valid', False):
            return token_object.get('data', token_object)
        else:
            # If no validation method found, return the token object itself
            return token_object

    except Exception:
        # Return None for any decoding/loading/validation errors
        return None

